"use strict";(globalThis.webpackChunkAditya_Vaidyam=globalThis.webpackChunkAditya_Vaidyam||[]).push([[368],{5376(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>s,default:()=>h,frontMatter:()=>a,metadata:()=>i,toc:()=>c});var i=t(4847),o=t(4848),r=t(8453);const a={},s="DIY: Core Animation",d={authorsImageUrls:[]},c=[];function l(e){const n={a:"a",code:"code",p:"p",strong:"strong",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:(0,o.jsx)(n.a,{href:"https://github.com/avaidyam/DIYAnimation",children:"(Check out the project over here.)"})}),"\n",(0,o.jsxs)(n.p,{children:["After having been a consumer of the ",(0,o.jsx)(n.strong,{children:"Core Animation"})," (originally ",(0,o.jsx)(n.strong,{children:"LayerKit"}),') framework for about a decade now, I began to wonder how it was designed and implemented under the hood. Not simply the surface details such as "it\'s rendered out of process" or "it handles the animation interpolation for you" or whatnot, but more specifically, ',(0,o.jsx)(n.strong,{children:"HOW"})," all of its beautiful bells and whistles translate into nitty gritty graphics ideas and associated draw calls. I figured the best way was to try to build it myself from scratch!"]}),"\n",(0,o.jsxs)(n.p,{children:["So I took iron to the anvil and decided to reimplement ",(0,o.jsx)(n.strong,{children:"Core Animation"})," in near-pure Swift -- that is, avoiding ",(0,o.jsx)(n.code,{children:"NSObject"}),"/Cocoa wherever possible. I didn't attempt to implement the entire API surface, such as ",(0,o.jsx)(n.code,{children:"CAAtom"}),", or the layout managers API (for that matter, layout managers have been remarked by Core Animation engineers as a bad idea anyways). I chose to design a closely matched, but overall Swift-ier API, such as ",(0,o.jsx)(n.code,{children:"Render.Value"}),". I haven't yet, however, implemented wrappers for all ",(0,o.jsx)(n.code,{children:"Codable"})," types, partially because ",(0,o.jsx)(n.strong,{children:"Core Animation"})," is implemented in C++ and some internal types such as ",(0,o.jsx)(n.code,{children:"CA::Render::Vector"})," are actually wrappers around ",(0,o.jsx)(n.code,{children:"float[]"}),", for example. Implementing serialization for a ",(0,o.jsx)(n.code,{children:"[Float]"})," in Swift is free, so we don't necessarily need these wrapper types. Some facilities like ",(0,o.jsx)(n.code,{children:"fence"}),"s to synchronize rendering between threads or processes, or ",(0,o.jsx)(n.code,{children:"slot"}),"s to share drawable items (if I recall correctly), aren't implemented yet simply because they're not required in ",(0,o.jsx)(n.strong,{children:"DIYAnimation"})," yet. Ultimately, only the Objective-C ",(0,o.jsx)(n.code,{children:"CA*"})," and the internal ",(0,o.jsx)(n.code,{children:"CA::Render::*"})," API surfaces are the same, as I've reimplemented the actual rendering (",(0,o.jsx)(n.code,{children:"CA::OGL::*"}),") in an entirely different way atop ",(0,o.jsx)(n.code,{children:"Metal"}),"."]}),"\n",(0,o.jsxs)(n.p,{children:["Another major departure from the C++ implementation is the use of ",(0,o.jsx)(n.code,{children:"XPC"})," serialization and transport over raw ",(0,o.jsx)(n.code,{children:"mach_msg"})," types and calls. While ",(0,o.jsx)(n.code,{children:"XPC"})," is best known for its service and connection facilities, ",(0,o.jsx)(n.strong,{children:"DIYAnimation"})," uses the ",(0,o.jsx)(n.code,{children:"xpc_pipe_t"})," object atop raw mach ports, a transport medium for serialized ",(0,o.jsx)(n.code,{children:"XPC"})," objects to be passed between threads and processes which underlies ",(0,o.jsx)(n.code,{children:"xpc_connection_t"}),". After writing an ",(0,o.jsx)(n.code,{children:"XPC"})," encoder and decoder pair in Swift, the ",(0,o.jsx)(n.code,{children:"XPCPipe"})," wrapper works with any ",(0,o.jsx)(n.code,{children:"Codable"})," with some notable exceptions involving patched implementations. Though I've got a mach shared memory object in Swift matching the original implementation, I'm instead using ",(0,o.jsx)(n.code,{children:"IOSurface"})," in a few places simply because it's easier to work with at the moment. I'll talk a bit more about the ",(0,o.jsx)(n.code,{children:"XPC"})," internals later, but for now I'll share a few tidbits I came across while implementing parts of ",(0,o.jsx)(n.strong,{children:"DIYAnimation"}),"."]}),"\n",(0,o.jsxs)(n.p,{children:["Since ",(0,o.jsx)(n.strong,{children:"Core Animation"})," doesn't deal with accelerated 2D graphics (i.e. the now-defunct ",(0,o.jsx)(n.code,{children:"QuartzGL"})," from ",(0,o.jsx)(n.strong,{children:"Core Graphics"}),"), text rendering, for example, is CPU-bound -- it's implemented in an identical manner in ",(0,o.jsx)(n.strong,{children:"DIYAnimation"}),". However, while ",(0,o.jsx)(n.code,{children:"QuartzGL"})," is indeed defunct, ",(0,o.jsx)(n.strong,{children:"Core Animation"})," does actually indirectly support accelerated drawing! To make a very long story short, non-accelerated/CPU-bound drawing is performed through ",(0,o.jsx)(n.code,{children:"CGContext"})," from ",(0,o.jsx)(n.code,{children:"Core Graphics"}),", which is actually just a wrapper around ",(0,o.jsx)(n.code,{children:"CGGState"}),", which manages the transparency layers and graphics state stack, and ",(0,o.jsx)(n.code,{children:"CGContextDelegate"}),", which handles conversion of Quartz draw calls into actual rasterization. (As a side-side-note, ",(0,o.jsx)(n.code,{children:"CGLayers"})," and transparency layers are essentially identical, but capture context state at different points in the drawing lifecycle.) ",(0,o.jsx)(n.code,{children:"CAWindowContextDelegate"})," is the delegate used by all ",(0,o.jsx)(n.code,{children:"CGContext"}),"s drawing to a Cocoa window, and ",(0,o.jsx)(n.code,{children:"CAIOSurfaceContextDelegate"})," is the delegate used by all ",(0,o.jsx)(n.code,{children:"CGContext"}),"s attached to a ",(0,o.jsx)(n.code,{children:"CALayer"})," that's currently accelerating drawing within ",(0,o.jsx)(n.code,{children:"-drawInContext:"}),". It accelerates drawing by buffering its queued draw calls until its associated layer needs to draw to screen, and subsequently thereafter, its associated ",(0,o.jsx)(n.code,{children:"IOSurface"})," needs to draw to screen."]}),"\n",(0,o.jsxs)(n.p,{children:["I've attempted to replicate window server functionality as seen in ",(0,o.jsx)(n.code,{children:"CAWindowServer"})," and ",(0,o.jsx)(n.code,{children:"CADisplay"}),", using ",(0,o.jsx)(n.code,{children:"CGS"})," windows (",(0,o.jsx)(n.code,{children:"CoreGraphicsServices"}),", now known as ",(0,o.jsx)(n.code,{children:"SkyLight"})," in macOS 11+), though it's done somewhat strangely at the moment. Not only does ",(0,o.jsx)(n.code,{children:"SkyLight"})," on macOS handle event routing and layer compositing like ",(0,o.jsx)(n.strong,{children:"Core Animation"})," on iOS, but also desktop management, spaces, the menu bar, cursors, and controlling the dock, and more on macOS. That's a lot of additional functionality that I'll be ignoring. In ",(0,o.jsx)(n.code,{children:"AppKit"}),", for example, invoking the modern drag and drop API eventually calls into ",(0,o.jsx)(n.code,{children:"HIServices"}),", the vestigial ",(0,o.jsx)(n.code,{children:"Carbon.framework"})," remnant underlying most of ",(0,o.jsx)(n.code,{children:"AppKit"}),", which then calls into the ",(0,o.jsx)(n.code,{children:"CoreDrag.framework"}),", which then creates a new ",(0,o.jsx)(n.code,{children:"CGSWindow"})," with the ",(0,o.jsx)(n.strong,{children:"SkyLight"})," window server, a new ",(0,o.jsx)(n.code,{children:"CAContext"})," to go with it (therefore enabling ",(0,o.jsx)(n.strong,{children:"Core Animation"})," embedding in that window), and a new root ",(0,o.jsx)(n.code,{children:"CALayer"}),". That layer is then what you see while dragging a file or anything else. The actual movement of data between one process to another (",(0,o.jsx)(n.code,{children:"NSPasteboard"})," in ",(0,o.jsx)(n.code,{children:"AppKit"}),") is actually implemented using ",(0,o.jsx)(n.code,{children:"CFMessagePort"})," in ",(0,o.jsx)(n.code,{children:"HIServices"})," - every AppKit-linked process has this port pair allocated for drag-and-drop or other pasteboard synchronization."]}),"\n",(0,o.jsxs)(n.p,{children:["Speaking of ",(0,o.jsx)(n.code,{children:"CGSWindow"})," and ",(0,o.jsx)(n.code,{children:"CAContext"}),", by the way, these two API are actually somewhat identical in some ways. ",(0,o.jsx)(n.code,{children:"AppKit"}),"'s ",(0,o.jsx)(n.code,{children:"NSWindow"})," wraps a ",(0,o.jsx)(n.code,{children:"CGSWindow"}),", and supports on-screen drawing through providing a ",(0,o.jsx)(n.code,{children:"CGContext"})," to its children ",(0,o.jsx)(n.code,{children:"NSView"}),"s. System events are passed from the ",(0,o.jsx)(n.code,{children:"SkyLight"})," window server to the most appropriate ",(0,o.jsx)(n.code,{children:"CGSWindow"})," (through a callback into the application's run loop) which then is translated and passed to the appropriate ",(0,o.jsx)(n.code,{children:"NSView"})," by that ",(0,o.jsx)(n.code,{children:"NSWindow"}),". The connection to the window server, ",(0,o.jsx)(n.code,{children:"CGSConnection"})," is actually explicit in all these API, and must be created by ",(0,o.jsx)(n.code,{children:"AppKit"})," for each thread that wants to manage on-screen elements. Each connection is recorded by the server in an identifier-based lookup table, and upon each call to the server, its originating connection's rights are validated for each resource modified or accessed by that call. ",(0,o.jsx)(n.code,{children:"SkyLight"})," actually uses ",(0,o.jsx)(n.strong,{children:"Mach Interface Generator (MIG)"})," to marshall these calls, and connections are actually just composed of a server request mach port and an on-demand client notification/event port. In ",(0,o.jsx)(n.strong,{children:"Core Animation"}),", however, ",(0,o.jsx)(n.code,{children:"CAContext"})," doesn't handle any drawing or rendering control itself, instead delegating this to its root ",(0,o.jsx)(n.code,{children:"CALayer"}),". It does control inter-context ordering (i.e. ordering root layers relative to all other on-screen root layers) and event routing when initialized connected to a remote window server instead of initialized as a local rendering context. So, CA windows (contexts) are equivalent to SkyLight windows, but while one SkyLight connection can control many windows, one CA connection may only control one CA window (context). In a way though, for quite some time now, ",(0,o.jsx)(n.code,{children:"AppKit"})," internal/private API has slowly been modernized to match ",(0,o.jsx)(n.strong,{children:"Core Animation"}),", with functions like ",(0,o.jsx)(n.code,{children:"NSWindowMark"})," mimicking ",(0,o.jsx)(n.code,{children:"CALayerMark"})," along with the recent addition of transactions. (With ",(0,o.jsx)(n.code,{children:"CGPixelAccess"})," and direct ",(0,o.jsx)(n.code,{children:"CGContext"})," drawing, ",(0,o.jsx)(n.code,{children:"SkyLight"})," actually has an analogous concept to ",(0,o.jsx)(n.code,{children:"CABackingStore"}),"; ",(0,o.jsx)(n.code,{children:"CA::Shape"})," too is essentially the same as ",(0,o.jsx)(n.code,{children:"CGSRegionObj"}),"/",(0,o.jsx)(n.code,{children:"CGRegion"}),".)"]}),"\n",(0,o.jsxs)(n.p,{children:["Anyways, the next steps for this project include adding ",(0,o.jsx)(n.code,{children:"CADynamicsBehavior"})," (probably hard, requiring ",(0,o.jsx)(n.code,{children:"box2d"})," or ",(0,o.jsx)(n.code,{children:"PhysicsKit"})," integration), ",(0,o.jsx)(n.code,{children:"CAStateController"})," (likely easy), ",(0,o.jsx)(n.code,{children:"CAPresentationModifier"})," (likely easy), and ",(0,o.jsx)(n.code,{children:"CAML"})," and ",(0,o.jsx)(n.code,{children:"CAPackage"})," support (likely easy... if using ",(0,o.jsx)(n.code,{children:"NSXMLParser"}),"). Though they've since been removed from ",(0,o.jsx)(n.strong,{children:"Core Animation"}),", ",(0,o.jsx)(n.code,{children:"CALight"})," and related lighting filters did used to exist, roughly matching SVG's ",(0,o.jsx)(n.code,{children:"feDiffuseLighting"})," and ",(0,o.jsx)(n.code,{children:"feSpecularLighting"}),", for example. They were meant to be used with ",(0,o.jsx)(n.code,{children:"CAMeshTransform"}),", which is also currently unimplemented. In summary, as you can see, there's a lot of private and some public API that are yet unimplemented, even though the groundwork has been laid. Take a look at the implementation details -- I'm sure you'll find them interesting, as they're mostly faithful to the original (decompiled) C++ implementation!"]})]})}function h(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>a,x:()=>s});var i=t(6540);const o={},r=i.createContext(o);function a(e){const n=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:a(e.components),i.createElement(r.Provider,{value:n},e.children)}},4847(e){e.exports=JSON.parse('{"permalink":"/blog/2019/02/19/","source":"@site/blog/2019-02-19.md","title":"DIY: Core Animation","description":"(Check out the project over here.)","date":"2019-02-19T00:00:00.000Z","tags":[],"readingTime":6.13,"hasTruncateMarker":true,"authors":[],"frontMatter":{},"unlisted":false,"prevItem":{"title":"On the debate of iOS vs. macOS","permalink":"/blog/2019/06/02/"},"nextItem":{"title":"An Exercise in Modern Cocoa Views","permalink":"/blog/2018/03/22/"}}')}}]);